local filename = ngx.var.arg_filename

-- Function to sanitize and resolve the file path
local function sanitize_path(file)
    local base_dir = "./files/"
    local resolved_path = base_dir .. file

    -- Normalize the path to prevent directory traversal
    resolved_path = resolved_path:gsub("/+", "/"):gsub("\\+", "/")
    resolved_path = resolved_path:gsub("%.%./", ""):gsub("%.%\\", "")
    
    -- Ensure the resolved path starts with the base directory
    if not resolved_path:find(base_dir, 1, true) then
        return nil
    end

    return resolved_path
end

local safe_path = sanitize_path(filename)

if not safe_path then
    ngx.say("Invalid file path.")
    return
end

local file, err = io.open(safe_path, "rb")
if not file then
    ngx.say("File not found: ", err)
    return
end

local content = file:read("*a")
file:close()

ngx.say(content)